VALUES
  ('social-worker-moex-00221', 'social-worker', 'social-worker-moex-114-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '各國於二次大戰之後所建立的諸多社會安全制度，主要以現金給付與實物給付形式提供服務對象 所需的服務與給付，另發展諸多「保護性立法」而成為福利國家的第三大支柱。對於「保護性立 法」之敘述，下列何者最為貼切？', '["藉由建立具有促進性與預防性之立法，保障人民的社會權、健康權、生存權等", "透過諸多相關法規的建立，確保民眾能夠普遍獲得所需的現金給付與福利服務之權利", "立法保障獲得給付者已經取得的福利服務與現金給付，以增進其運用服務與給付的選擇權", "該等立法可簡化行政處理、審查與評估程序，以保障經濟弱勢者取得服務與給付的社會權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "b5736cd5aeb1", "answer_pdf_sha1": "0dc235ff4e11", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00222', 'social-worker', 'social-worker-moex-114-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '在福利混合經濟的論述中，納入透過稅賦形式所提供的福利服務與給付，以減輕家戶與個人的負 擔。我國並未提供下列何種稅賦福利？', '["長期照顧服務費抵減", "人身保險費抵減", "工作所得租稅抵減（EITC）", "依附者扶養抵減"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "b5736cd5aeb1", "answer_pdf_sha1": "0dc235ff4e11", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00223', 'social-worker', 'social-worker-moex-114-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '下列的福利服務或現金給付之中，何者屬於由民間提供財務負擔、政府提供服務或給付之性質？', '["非營利組織所提供的緊急安置服務", "社會救助法所提供的急難救助", "由社會局所提供的早期療育服務", "地方政府愛心專戶所提供的福利服務"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "b5736cd5aeb1", "answer_pdf_sha1": "0dc235ff4e11", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00224', 'social-worker', 'social-worker-moex-114-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '1980年代之後，西方福利國家的福利供給開始從福利科層和專業主義轉向福利多元主義，下列敘 述何者正確？', '["福利科層與專業主義著重競爭", "福利科層與專業主義著重績效要求", "福利多元主義注重服務提供的一致性", "福利多元主義強調應該由不同部門提供服務"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "b5736cd5aeb1", "answer_pdf_sha1": "0dc235ff4e11", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00225', 'social-worker', 'social-worker-moex-114-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依我國國民年金法規定，國民年金保險的保險人，目前由下列那個機關負責辦理？', '["中央健康保險署", "勞工保險局", "社會保險司", "銓敘部"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "b5736cd5aeb1", "answer_pdf_sha1": "0dc235ff4e11", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00226', 'social-worker', 'social-worker-moex-114-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關從「科層－專業主義守門人取向」到「新管理主義顧客取向」變化的敘述，下列何者正確？', '["從需求取向，往預算取向變化", "從預算沒有彈性，往預算具有彈性變化", "從量身打造服務，往有效率提高服務供給量變化", "從基於個人選擇，往最佳利用納稅人稅賦變化"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "b5736cd5aeb1", "answer_pdf_sha1": "0dc235ff4e11", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00227', 'social-worker', 'social-worker-moex-114-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關福利服務領域中最佳價值所倡導的5Cs組合，下列何者正確？', '["合作績效、競爭績效、審慎、競爭、回應", "規劃績效、比較績效、避險、標準、合作", "溝通績效、加乘績效、回應、召喚、避險", "挑戰績效、比較績效、徵詢、競爭、合作"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "b5736cd5aeb1", "answer_pdf_sha1": "0dc235ff4e11", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
