  ('social-worker-moex-00230', 'social-worker', 'social-worker-moex-114-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '下列何者非屬社會津貼制度的特質？', '["對符合某種資格之人口群均可領取", "財務規模大，行政成本也高", "採取假定需求原則", "給付採取定額均一給付"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "b5736cd5aeb1", "answer_pdf_sha1": "0dc235ff4e11", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
